def setup_logging(
    log_dir: str = "/var/log/myapp",
    log_filename: str = "application.log",
    max_bytes: int = 10 * 1024 * 1024,  # 10 MB
    backup_count: int = 5,
    log_level: int = logging.DEBUG,
    file_permissions: int = 0o640,
    dir_permissions: int = 0o750,
):
    """
    Set up application logging with file rotation and proper permissions.

    Args:
        log_dir: Directory to store log files
        log_filename: Name of the log file
        max_bytes: Maximum size of each log file before rotation
        backup_count: Number of backup files to keep
        log_level: Logging level
        file_permissions: Unix file permissions for log files (owner rw, group r)
        dir_permissions: Unix directory permissions for log directory
    """
    # Create log directory if it doesn't exist
    log_path = Path(log_dir)
    try:
        log_path.mkdir(parents=True, exist_ok=True)
        os.chmod(log_dir, dir_permissions)
    except PermissionError:
        # Fallback to user's home directory if /var/log is not writable
        log_dir = os.path.join(Path.home(), ".myapp", "logs")
        log_path = Path(log_dir)
        log_path.mkdir(parents=True, exist_ok=True)
        os.chmod(log_dir, dir_permissions)
        print(f"Warning: Using fallback log directory: {log_dir}", file=sys.stderr)

    log_file = os.path.join(log_dir, log_filename)

    # Create the root logger
    logger = logging.getLogger("myapp")
    logger.setLevel(log_level)

    # Clear any existing handlers
    logger.handlers.clear()

    # Define log format
    detailed_formatter = logging.Formatter(
        fmt="%(asctime)s | %(levelname)-8s | %(name)s | %(module)s:%(funcName)s:%(lineno)d | %(message)s",
        datefmt="%Y-%m-%d %H:%M:%S",
    )

    console_formatter = logging.Formatter(
        fmt="%(asctime)s | %(levelname)-8s | %(message)s",
        datefmt="%H:%M:%S",
    )

    # --- Rotating File Handler (size-based rotation) ---
    rotating_file_handler = logging.handlers.RotatingFileHandler(
        filename=log_file,
        maxBytes=max_bytes,
        backupCount=backup_count,
        encoding="utf-8",
    )
    rotating_file_handler.setLevel(logging.DEBUG)
    rotating_file_handler.setFormatter(detailed_formatter)

    # Set file permissions on the log file
    _set_file_permissions(log_file, file_permissions)

    # Override the rotation method to set permissions on rotated files
    original_doRollover = rotating_file_handler.doRollover

    def custom_doRollover():
        original_doRollover()
        # Set permissions on all log files after rotation
        _set_permissions_on_all_logs(log_dir, log_filename, file_permissions)

    rotating_file_handler.doRollover = custom_doRollover

    # --- Timed Rotating File Handler (time-based rotation) ---
    timed_log_file = os.path.join(log_dir, "application_timed.log")
    timed_rotating_handler = logging.handlers.TimedRotatingFileHandler(
        filename=timed_log_file,
        when="midnight",  # Rotate at midnight
        interval=1,       # Every 1 day
        backupCount=30,   # Keep 30 days of logs
        encoding="utf-8",
    )
    timed_rotating_handler.setLevel(logging.INFO)
    timed_rotating_handler.setFormatter(detailed_formatter)
    timed_rotating_handler.suffix = "%Y-%m-%d"

    _set_file_permissions(timed_log_file, file_permissions)

    # --- Error File Handler (separate file for errors) ---
    error_log_file = os.path.join(log_dir, "errors.log")
    error_file_handler = logging.handlers.RotatingFileHandler(
        filename=error_log_file,
        maxBytes=5 * 1024 * 1024,  # 5 MB
        backupCount=10,
        encoding="utf-8",
    )
    error_file_handler.setLevel(logging.ERROR)
    error_file_handler.setFormatter(detailed_formatter)

    _set_file_permissions(error_log_file, file_permissions)

    # --- Console Handler ---
    console_handler = logging.StreamHandler(sys.stdout)
    console_handler.setLevel(logging.INFO)
    console_handler.setFormatter(console_formatter)

    # Add all handlers to the logger
    logger.addHandler(rotating_file_handler)
    logger.addHandler(timed_rotating_handler)
    logger.addHandler(error_file_handler)
    logger.addHandler(console_handler)

    logger.info("Logging system initialized successfully.")
    logger.info(f"Log directory: {log_dir}")
    logger.info(f"Log file: {log_file}")
    logger.info(f"Max file size: {max_bytes / (1024 * 1024):.1f} MB")
    logger.info(f"Backup count: {backup_count}")
    logger.info(f"File permissions: {oct(file_permissions)}")

    return logger


def _set_file_permissions(filepath: str, permissions: int):
    """Set file permissions on a log file."""
    try:
        if os.path.exists(filepath):
            os.chmod(filepath, permissions)
        else:
            # Create the file and set permissions
            fd = os.open(filepath, os.O_CREAT | os.O_WRONLY, permissions)
            os.close(fd)
    except OSError as e:
        print(f"Warning: Could not set permissions on {filepath}: {e}", file=sys.stderr)


def _set_permissions_on_all_logs(log_dir: str, base_filename: str, permissions: int):
    """Set permissions on all log files including rotated ones."""
    try:
        for filename in os.listdir(log_dir):
            filepath = os.path.join(log_dir, filename)
            if os.path.isfile(filepath):
                os.chmod(filepath, permissions)
    except OSError as e:
        print(f"Warning: Could not set permissions on log files: {e}", file=sys.stderr)


def get_file_permissions_string(filepath: str) -> str:
    """Get human-readable file permissions string."""
    try:
        st = os.stat(filepath)
        mode = st.st_mode
        permissions = stat.filemode(mode)
        return permissions
    except OSError:
        return "N/A"


def verify_log_setup(log_dir: str):
    """Verify and display the log setup details."""
    print("\n" + "=" * 60)
    print("LOG SETUP VERIFICATION")
    print("=" * 60)

    if os.path.exists(log_dir):
        print(f"\nLog Directory: {log_dir}")
        print(f"Directory Permissions: {get_file_permissions_string(log_dir)}")
        print(f"\nLog Files:")
        print("-" * 50)

        for filename in sorted(os.listdir(log_dir)):
            filepath = os.path.join(log_dir, filename)
            if os.path.isfile(filepath):
                size = os.path.getsize(filepath)
                perms = get_file_permissions_string(filepath)
                print(f"  {filename:<35} {perms} {size:>10} bytes")
    else:
        print(f"Log directory does not exist: {log_dir}")

    print("=" * 60 + "\n")


